/// One baked region: its lock-item name, warp-grace open flag (None = geometry known but no
/// resolved open flag, so the region cannot be gated), and its play_region ids.
pub struct BakedRegionLock {
    pub region: &'static str,
    pub lock_item: &'static str,
    pub open_flag: Option<u32>,
    pub play_regions: &'static [i32],
}

