/// Look a lock-item NAME (e.g. "Caelid Lock") up in the baked table.
pub fn by_lock_item(name: &str) -> Option<&'static BakedRegionLock> {
    REGION_LOCKS.iter().find(|r| r.lock_item == name)
}

#[cfg(test)]
mod generated_tests {
    use super::*;

    #[test]
    fn nonempty_sorted_unique() {
        assert!(!REGION_LOCKS.is_empty());
        assert!(REGION_LOCKS.windows(2).all(|w| w[0].region < w[1].region));
        let mut ids: Vec<i32> = REGION_LOCKS.iter().flat_map(|r| r.play_regions.iter().copied()).collect();
        let n = ids.len();
        ids.sort_unstable();
        ids.dedup();
        assert_eq!(ids.len(), n, "play_region ids must be globally unique");
        assert!(REGION_LOCKS.iter().all(|r| !r.play_regions.is_empty()));
    }

    #[test]
    fn lock_items_follow_the_naming_convention() {
        for r in REGION_LOCKS {
            assert_eq!(r.lock_item, format!("{} Lock", r.region));
            assert!(by_lock_item(r.lock_item).is_some());
        }
        assert!(by_lock_item("No Such Region Lock").is_none());
    }
}
